import {BrowserRouter, Routes, Route} from 'react-router-dom';
import {Container} from 'react-bootstrap';
function App() {
    return (
        <BrowserRouter>
        <Container>
            <Routes>
                <Route path="/" element={<ListProduct />} />
                <Route path="/add" element={<AddProduct />} />
                <Route path="/edit/:id" element={<EditProduct />} />
            </Routes>
        </Container>
        </BrowserRouter>
    )
}

export default App;
